type ReaderEngine = 'native' | 'kokoro' | 'chirp' | 'rendered';
type ReaderState = 'idle' | 'loading' | 'reading' | 'paused';
type Sentence = { raw:string; text:string; start:number; end:number };
type ReaderMount = { referenceId:string; language:string; container:HTMLElement; button:HTMLButtonElement; stopButton?:HTMLButtonElement; report:(message:string,tone?:'ready'|'saving'|'error')=>void; chirpEnabled:boolean };
type NarrationProvider='kokoro'|'chirp';
type NarrationSegment={index:number;url:string;sizeBytes:number;startOffset:number|null;endOffset:number|null};
type ReaderChapter={title:string;offset:number;time:number};

const SETTINGS_KEY='seshat.read-aloud.v1';
const MODEL_ID='onnx-community/Kokoro-82M-v1.0-ONNX';
const readerIcon=(name:'speaker'|'bookmark'|'slower'|'faster'|'play'|'stop')=>({
  speaker:'<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M4 10v4h4l5 4V6L8 10H4Z"/><path d="M16 9.5c1.2 1.4 1.2 3.6 0 5M18.5 7c2.6 2.8 2.6 7.2 0 10"/></svg>',
  bookmark:'<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M7 4.5h10v15l-5-3.2-5 3.2v-15Z"/></svg>',
  slower:'<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M16 6 10 12l6 6"/><path d="M8 6v12"/></svg>',
  faster:'<svg viewBox="0 0 24 24" aria-hidden="true"><path d="m8 6 6 6-6 6"/><path d="M16 6v12"/></svg>',
  play:'<svg viewBox="0 0 24 24" aria-hidden="true"><path class="reader-icon-fill" d="m8 5 11 7-11 7V5Z"/></svg>',
  stop:'<svg viewBox="0 0 24 24" aria-hidden="true"><rect class="reader-icon-fill" x="6" y="6" width="12" height="12" rx="1"/></svg>',
})[name];
export const visibleChapterLabelIndexes=(count:number,maximum:number)=>{
  const total=Math.max(0,Math.floor(count)),limit=Math.max(0,Math.floor(maximum));
  if(!total||!limit)return[];
  if(total<=limit)return Array.from({length:total},(_,index)=>index);
  if(limit===1)return[0];
  return [...new Set(Array.from({length:limit},(_,index)=>Math.round(index*(total-1)/(limit-1))))];
};
export const KOKORO_VOICES=[
  {id:'ef_dora',label:'Dora · español · local'},
  {id:'em_alex',label:'Alex · español · local'},
  {id:'em_santa',label:'Santa · español · local'},
  {id:'af_heart',label:'Heart · English · local'},
  {id:'af_bella',label:'Bella · English · local'},
  {id:'am_michael',label:'Michael · English · local'},
];

type ReaderSettings={engine:ReaderEngine;voice:string;rate:number;nativeVoices:string[]};
const readSettings=():ReaderSettings=>{try{return{engine:'native',voice:'',rate:1,nativeVoices:[],...JSON.parse(localStorage.getItem(SETTINGS_KEY)||'{}')}}catch{return{engine:'native',voice:'',rate:1,nativeVoices:[]}}};
export const steppedReaderRate=(rate:number,delta:number)=>Math.max(.5,Math.min(2,Math.round((Number(rate||1)+delta)*4)/4));
export const normalizeReaderLanguage=(value:string)=>{const normalized=String(value||'').trim().toLowerCase();const aliases:Record<string,string>={spa:'es',spanish:'es','español':'es',castellano:'es',eng:'en',english:'en','inglés':'en',fra:'fr',fre:'fr',french:'fr','français':'fr',deu:'de',ger:'de',german:'de','alemán':'de',ita:'it',italian:'it',por:'pt',portuguese:'pt',cat:'ca',catalan:'ca',nld:'nl',dut:'nl',dutch:'nl',lat:'la',latin:'la'};if(aliases[normalized])return aliases[normalized];try{return new Intl.Locale(normalized.replace('_','-')).language.toLowerCase();}catch{return normalized.slice(0,2);}};
const languageCode=normalizeReaderLanguage;
const cleanSpeech=(value:string)=>normalizeBrowserSpeechText(value
  .replace(/^---[\s\S]*?---\s*/,'').replace(/```[\s\S]*?```/g,' ')
  .replace(/(?:^|\n)\s*(?:(?:page|pages|p[áa]g(?:ina)?s?|p[áa]g\.)\s*)?\d+(?:\s*(?:of|de)\s*\d+)?\s*(?=\n|$)/gimu,' ')
  .replace(/!\[[^\]]*\]\([^)]*\)/g,' ').replace(/\[([^\]]+)\]\([^)]*\)/g,'$1')
  .replace(/https?:\/\/\S+/g,' ').replace(/^\s{0,3}(?:#{1,6}|>|[-*+]\s|\d+[.)]\s)/gm,'')
  .replace(/[*_`~]/g,''));

const groupedSpeech=(sentences:Sentence[],maxBytes:number)=>{const encoder=new TextEncoder();const groups:string[]=[];let current='';for(const sentence of sentences){const candidate=`${current}${current?' ':''}${sentence.text}`;if(current&&encoder.encode(candidate).length>maxBytes){groups.push(current);current=sentence.text;}else current=candidate;}if(current)groups.push(current);return groups;};
export const narrationCharacterCount=(source:string,language='en')=>billableCharacterCount(groupedSpeech(splitReadingSentences(source,language),4000).join(''));

const wavBlob=(parts:Float32Array[],sampleRate:number)=>{const samples=parts.reduce((sum,item)=>sum+item.length,0);const buffer=new ArrayBuffer(44+samples*2);const view=new DataView(buffer);const text=(offset:number,value:string)=>{for(let index=0;index<value.length;index+=1)view.setUint8(offset+index,value.charCodeAt(index));};text(0,'RIFF');view.setUint32(4,36+samples*2,true);text(8,'WAVE');text(12,'fmt ');view.setUint32(16,16,true);view.setUint16(20,1,true);view.setUint16(22,1,true);view.setUint32(24,sampleRate,true);view.setUint32(28,sampleRate*2,true);view.setUint16(32,2,true);view.setUint16(34,16,true);text(36,'data');view.setUint32(40,samples*2,true);let offset=44;for(const part of parts)for(const sample of part){const clipped=Math.max(-1,Math.min(1,sample));view.setInt16(offset,clipped<0?clipped*0x8000:clipped*0x7fff,true);offset+=2;}return new Blob([buffer],{type:'audio/wav'});};

export const splitReadingSentences=(source:string,language='en'):Sentence[]=>{
  const lineKey=(value:string)=>value.normalize('NFKC').toLowerCase().replace(/\s+/g,' ').trim();const counts=new Map<string,number>();for(const line of source.split(/\r?\n|\f/)){const key=lineKey(line);if(key.length>=3&&key.length<=100&&key.split(/\s+/).length<=14&&!/[.!?]$/.test(key))counts.set(key,(counts.get(key)||0)+1);}const runningLines=new Set([...counts].filter(([,count])=>count>=3).map(([line])=>line));
  const segments:Array<{segment:string;index:number}>=[];
  try{const Segmenter=(Intl as any).Segmenter;const segmenter=new Segmenter(language||'en',{granularity:'sentence'});for(const value of segmenter.segment(source))segments.push({segment:value.segment,index:value.index});}
  catch{let cursor=0;for(const segment of source.match(/[^.!?\n]+(?:[.!?]+|\n+|$)/g)||[]){const index=source.indexOf(segment,cursor);segments.push({segment,index});cursor=index+segment.length;}}
  return segments.map(({segment,index})=>{const withoutRunningHeaders=segment.split(/(\r?\n|\f)/).filter((line)=>!runningLines.has(lineKey(line))).join('');return{raw:segment,text:cleanSpeech(withoutRunningHeaders),start:index,end:index+segment.length};}).filter((item)=>item.text.length>1&&item.text.length<1800);
};

