  async loadText(){if(!this.mount)return;const response=await fetch(`/api/library/${encodeURIComponent(this.mount.referenceId)}/artifact/markdown`,{cache:'no-store'});if(!response.ok)throw new Error('Extracted text is required before reading aloud.');this.source=await response.text();this.sentences=splitReadingSentences(this.source,this.mount.language);this.loadedReferenceId=this.mount.referenceId;if(!this.sentences.length)throw new Error('No readable sentences were found.');this.index=0;const annotations=await fetch(`/api/library/${encodeURIComponent(this.mount.referenceId)}/annotations`).then((result)=>result.ok?result.json():null).catch(()=>null);const mark=(annotations?.annotations||[]).filter((item:any)=>item.noteType==='reading-mark').sort((a:any,b:any)=>String(b.createdAt).localeCompare(String(a.createdAt)))[0];if(mark){const next=this.sentences.findIndex((sentence)=>sentence.start>=Number(mark.endOffset||0));if(next>=0)this.index=next;}}
  async start(fromIndex?:number){if(!this.mount)return;if(this.state!=='idle')this.stop(false);const stored=readSettings(),settings={...stored,engine:stored.engine==='chirp'&&!this.mount.chirpEnabled?'native':stored.engine} as ReaderSettings;if(settings.engine==='kokoro'&&this.kokoroRendering){this.mount.report('Kokoro is rendering · choose Browser/Microsoft or Chirp for simultaneous reading','error');return;}this.activeEngine=settings.engine;this.state='loading';this.paintButton();this.mount.report('preparing read aloud…','saving');try{await this.loadText();if(Number.isFinite(fromIndex))this.index=Math.max(0,Math.min(this.sentences.length-1,Math.floor(fromIndex!)));const token=++this.token;if(settings.engine==='kokoro')await this.runKokoro(token);else if(settings.engine==='chirp')await this.runChirp(token);else await this.runNative(token);}catch(error){this.activeEngine=null;this.state='idle';this.paintButton();this.mount?.report(error instanceof Error?error.message:'Read aloud failed','error');}}
  async offerPlayFrom(event:PointerEvent,mount:ReaderMount){const target=event.target as HTMLElement|null;if(!target||target.closest('button,a,input,select,textarea,dialog,.read-aloud-caption,.play-from-tooltip'))return;const textTarget=target.closest<HTMLElement>('pre,.textLayer span');if(!textTarget)return;if(window.getSelection()?.toString().trim())return;this.mount=mount;if(this.loadedReferenceId!==mount.referenceId||!this.sentences.length)try{await this.loadText();}catch{return;}let sentenceIndex=-1;const pre=textTarget.closest('pre');if(pre){const doc=document as any;const caret=doc.caretPositionFromPoint?.(event.clientX,event.clientY);const rangeAtPoint=caret?null:doc.caretRangeFromPoint?.(event.clientX,event.clientY);const node=caret?.offsetNode||rangeAtPoint?.startContainer,offset=caret?.offset??rangeAtPoint?.startOffset;if(node&&pre.contains(node)&&Number.isFinite(offset)){const range=document.createRange();range.selectNodeContents(pre);try{range.setEnd(node,offset);const sourceOffset=range.toString().length;sentenceIndex=this.sentences.findIndex((sentence)=>sourceOffset>=sentence.start&&sourceOffset<=sentence.end);}catch{}}}if(sentenceIndex<0){const clicked=cleanSpeech(textTarget.textContent||'').toLowerCase(),words=new Set(clicked.split(/\s+/).filter((word)=>word.length>3));let best=-1,bestScore=0;this.sentences.forEach((sentence,index)=>{const candidate=sentence.text.toLowerCase();const score=(clicked&&candidate.includes(clicked)?100:0)+[...words].filter((word)=>candidate.includes(word)).length-Math.abs(index-this.index)*.0001;if(score>bestScore){bestScore=score;best=index;}});sentenceIndex=best;}if(sentenceIndex<0)return;this.playTooltip?.remove();const tooltip=document.createElement('button');tooltip.type='button';tooltip.className='play-from-tooltip';tooltip.textContent='Play from here';tooltip.style.left=`${Math.max(8,Math.min(window.innerWidth-132,event.clientX+8))}px`;tooltip.style.top=`${Math.max(8,Math.min(window.innerHeight-42,event.clientY+8))}px`;tooltip.onclick=(click)=>{click.preventDefault();click.stopPropagation();tooltip.remove();if(this.playTooltip===tooltip)this.playTooltip=null;void this.start(sentenceIndex);};this.playTooltip=tooltip;(document.fullscreenElement||document.body).appendChild(tooltip);window.setTimeout(()=>{if(this.playTooltip===tooltip){tooltip.remove();this.playTooltip=null;}},5000);}
